sql:
SELECT AVG(confidence_level) AS average_confidence, MAX(confidence_level) AS max_confidence
FROM geological_data
WHERE analyzed_by = 124;

SELECT company_id, sample_id, score
   FROM geological_data
   ORDER BY score DESC;

SELECT company_lithocode
FROM geological_data
WHERE sample_id = 0;

SELECT COUNT(DISTINCT company_lithocode) AS distinct_lithocodes
FROM geological_data
WHERE analysis_date > '2023-04-01';

external_knowledge:
- 'Excavators' refers to companies conducting geological surveys; 
- 'Unearthed the hidden treasures' refers to finding geological data; 
- 'Finished digging' refers to surveys with a status of 'Completed';
- 'Confident in their findings' refers to the confidence level in the analysis.

- The lithology classification is a way to categorize rock units based on their composition and structure; 
- The score of a sample is a measure of its quality or relevance; 
- Geological formation refers to a distinct body of rock that has a unified set of characteristics; 
- The age of the sample is its estimated age based on geological analysis.
